const data = $input.first().json;
const pendingData = $('Get Next Pending Row').first().json;
const selectedClips = data.selected_clips || [];

const MIN_SECS = 17;
const MAX_SECS = 28;
const BASE_VIDEO_SECS = 3;
const BASE_IMAGE_SECS = 2;

if (selectedClips.length === 0) throw new Error('No selected_clips in travel-media response');

const picked = selectedClips.map(clip => ({
  source: 'url',
  url: clip.url,
  media_type: clip.type,
  title: clip.title || '',
  caption_text: clip.caption_text || '',
}));

const videoCount = picked.filter(p => p.media_type === 'video').length;
const imageCount = picked.filter(p => p.media_type === 'image').length;
const baseDuration = videoCount * BASE_VIDEO_SECS + imageCount * BASE_IMAGE_SECS;

let clipVideo = BASE_VIDEO_SECS;
let clipImage = BASE_IMAGE_SECS;

if (baseDuration < MIN_SECS) {
  const scale = MIN_SECS / Math.max(baseDuration, 1);
  clipVideo = Math.round(BASE_VIDEO_SECS * scale * 10) / 10;
  clipImage = Math.round(BASE_IMAGE_SECS * scale * 10) / 10;
} else if (baseDuration > MAX_SECS) {
  const scale = MAX_SECS / baseDuration;
  clipVideo = Math.round(BASE_VIDEO_SECS * scale * 10) / 10;
  clipImage = Math.round(BASE_IMAGE_SECS * scale * 10) / 10;
}

const estimatedDuration = videoCount * clipVideo + imageCount * clipImage;

return [{
  json: {
    picked_items: picked,
    clip_seconds_video: String(clipVideo),
    clip_seconds_image: String(clipImage),
    total_items: picked.length,
    estimated_duration_secs: estimatedDuration,
    hook_caption: data.user_query || '',
    row_index: pendingData.row_index,
    destination: pendingData.destination,
  }
}];

