const reelData = $('Generate Reel (FFmpeg)').first().json;
const pickData = $('Pick Best Media Items').first().json;
const musicData = $('Fetch Music Track (Jamendo)').first().json;

// Caption may be missing if Groq failed (continueOnFail) — use safe defaults
let captionData = {};
try { captionData = $('Generate Caption & Hashtags (AI)').first().json; } catch(e) {}
let ytMeta = {};
try { ytMeta = $('Generate YouTube Metadata (AI)').first().json; } catch(e) {}

const destination = pickData.destination || '';
const title = captionData.title || destination;
const caption = captionData.caption || `Discover the best of ${destination}. Visit budgetwing.com for cheap flights.`;
const hashtags = captionData.hashtags || [];
const hashtag_block = captionData.hashtag_block || '';
const keywords = captionData.keywords || '';
const formatted_post = captionData.formatted_post || `${caption}\n\n.\n.\n.\n${hashtag_block}`;

return [{ json: {
  destination,
  video_url: reelData.video_url || '',
  title,
  caption,
  hashtags,
  hashtag_block,
  keywords,
  formatted_post,
  char_count: captionData.char_count || formatted_post.length,
  within_limit: captionData.within_limit !== false,
  reel_duration_secs: pickData.estimated_duration_secs || 0,
  row_index: pickData.row_index,
  groq_model: captionData.groq_model || '',
  place_names: pickData.place_names || [],
  music_source: musicData.source || 'none',
  music_title: musicData.title || '',
  music_artist: musicData.artist || '',
  youtube_title: ytMeta.youtube_title || '',
  youtube_description: ytMeta.youtube_description || '',
  youtube_tags: ytMeta.youtube_tags || [],
  youtube_pinned_comment: ytMeta.youtube_pinned_comment || '',
  youtube_title_variations: ytMeta.youtube_title_variations || [],
} }];

const saveData = $('Save Preview').first().json;
const previewId = saveData.preview_id;
const previewUrl = 'http://localhost:8000/instagram-preview/' + previewId;
const assembleData = $('Assemble Preview Data').first().json;
const musicSource = assembleData.music_source || 'none';
const musicTitle = assembleData.music_title || '';
const musicArtist = assembleData.music_artist || '';
const ytTitle = assembleData.youtube_title || '';
console.log('\n📋 PREVIEW READY');
console.log('Preview URL :', previewUrl);
if (musicSource !== 'none') {
  console.log('Music [' + musicSource + ']:', musicTitle + (musicArtist ? ' — ' + musicArtist : ''));
}
if (ytTitle) {
  console.log('YT Title    :', ytTitle);
}
console.log('Excel row marked done ✓');
console.log('Publishing to Instagram + YouTube now…');
return [{ json: { preview_id: previewId, preview_url: previewUrl } }];

const previewId = $('Preview URL').first().json.preview_id;
const previewUrl = $('Preview URL').first().json.preview_url;

let igMediaId = '—', igStatus = 'unknown';
let ytVideoId = '—', ytStatus = 'skipped';

try {
  const igResult = $('Publish to Instagram').first().json;
  igMediaId = igResult.ig_media_id || igResult.detail || igResult.error?.message || '—';
  igStatus = igResult.ig_media_id ? 'ok' : 'failed';
} catch (e) {
  igStatus = 'error: ' + e.message;
}

try {
  const ytResult = $('Publish to YouTube Shorts').first().json;
  ytVideoId = ytResult.youtube_video_id || ytResult.id || ytResult.detail || '—';
  ytStatus = (ytResult.youtube_video_id || ytResult.id) ? 'ok' : 'failed';
} catch (e) {
  ytStatus = igStatus === 'failed' ? 'skipped (IG failed)' : 'error: ' + e.message;
}

console.log('\n🎉 PUBLISH RESULT');
console.log('Preview URL  :', previewUrl);
console.log('IG Media ID  :', igMediaId, '(' + igStatus + ')');
console.log('YT Video ID  :', ytVideoId, '(' + ytStatus + ')');

return [{ json: {
  status: igStatus === 'ok' ? 'published' : 'ig_failed',
  preview_id: previewId,
  preview_url: previewUrl,
  ig_media_id: igMediaId !== '—' ? igMediaId : '',
  ig_status: igStatus,
  yt_video_id: ytVideoId !== '—' ? ytVideoId : '',
  yt_status: ytStatus,
} }];

